CREATE TABLE IF NOT EXISTS continuity_plans(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,code text NOT NULL,name text NOT NULL,type text NOT NULL CHECK(type IN ('bcp','dr')),owner text NOT NULL,status text NOT NULL DEFAULT 'draft',business_service text NOT NULL DEFAULT '',rto_minutes int NOT NULL CHECK(rto_minutes>=0),rpo_minutes int NOT NULL CHECK(rpo_minutes>=0),dependencies jsonb NOT NULL DEFAULT '[]'::jsonb,approved_by text NOT NULL DEFAULT '',approved_at timestamptz,activated_at timestamptz,next_exercise_at timestamptz,metadata jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),UNIQUE(tenant_id,code));
CREATE TABLE IF NOT EXISTS recovery_procedures(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,plan_id uuid NOT NULL,name text NOT NULL,sort_order int NOT NULL DEFAULT 0,steps jsonb NOT NULL,owner text NOT NULL DEFAULT '',checklist jsonb NOT NULL DEFAULT '[]'::jsonb,metadata jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS continuity_exercises(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,plan_id uuid NOT NULL,name text NOT NULL,type text NOT NULL,status text NOT NULL DEFAULT 'planned',scheduled_at timestamptz NOT NULL,started_at timestamptz,completed_at timestamptz,actual_rto_minutes int,actual_rpo_minutes int,findings jsonb NOT NULL DEFAULT '[]'::jsonb,evidence jsonb NOT NULL DEFAULT '[]'::jsonb,facilitator text NOT NULL DEFAULT '',created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS idx_continuity_plan_exercise ON continuity_plans(tenant_id,status,next_exercise_at);CREATE INDEX IF NOT EXISTS idx_continuity_exercise_status ON continuity_exercises(tenant_id,status,scheduled_at);
